//-------------------------------------------------------------------------
// 팝업
//-------------------------------------------------------------------------
scwin.f_PopUp = function (disGubun, chgGubun) {

    var rtnList = new Array();

    switch (disGubun){
        case 1:		//거래처 팝업(Search Partner)
            udc_pncd.ilCommonPopUp(scwin.callbackEngClntInfo,    		// XML상의 SELECT ID	                                                   							
                                    cnd_ed_pncd.getValue().trim(),        // 화면에서의 ??? Code Element의	Value                                  
                                    cnd_ed_pnnm.getValue(),             // 화면에서의 ??? Name Element의	Value                                  
                                    chgGubun,                       // 결과가 1건 일때  원도우를	AutoClose 여부	(T:Close,F:Opened)         
                                    '5',                            // 검색 결과	컬럼의 보여주는	개수 (SELECT절의 순서) MAX:10 - default (2)
                                    'Partner',                 		// Title순서	                                                           
                                    '140,300',                      // 보여주는 각 컬럼들의 폭	                                               
                                    null,                           // 컬럼중에서 숨기는	컬럼 지정	                                       
                                    null,                           // SQL절의 WHERE절에	원하는 조건을 선택함 MAX:8개까지 가능              
                                    '500',                          // POP-UP뛰을때 원도우의	사용자 정의	폭                                 
                                    '500',                          // POP-UP뛰을때 우도우의	사용자 정의	높이	                           
                                    null,                           // 윈도우 위치 Y좌표	                                                   
                                    null,                           // 윈도우 위치 X좌표                                                       
                                    null,                           // 중복체크여부	("F")                                                      
                                    'F',                            // 전체검색허용여부	("F")                                                  
                                    'Partner Search,Partner Code,Partner Name');                          // POP-UP Window Title 검색어1,2	 ("Win타이틀,첫번검색Nm,두번?검색Nm")  

            //cfSetReturnValue(rtnList, cnd_ed_pncd, cnd_txt_pnnm);

            break;					

        case 2:		//거래처 팝업(Partner)
            pParam = ed_pncd.getValue().trim();
            udc_pseq.ilCommonPopUp(scwin.callbackClntPicInfo,			// XML상의 SELECT ID	                                                   
                                    ed_pseq.getValue().trim(),            // 화면에서의 ??? Code Element의	Value                                  
                                    ed_pattn.getValue(),                // 화면에서의 ??? Name Element의	Value                                  
                                    chgGubun,                       // 결과가 1건 일때  원도우를	AutoClose 여부	(T:Close,F:Opened)         
                                    '2',                            // 검색 결과	컬럼의 보여주는	개수 (SELECT절의 순서) MAX:10 - default (2)
                                    "PIC", 		                	// Title순서	                                                           
                                    //'80,200,120,300',             // 보여주는 각 컬럼들의 폭	                                               
                                    '100,350',               		// 보여주는 각 컬럼들의 폭	                                               
                                    null,                           // 컬럼중에서 숨기는	컬럼 지정	                                       
                                    pParam,                         // SQL절의 WHERE절에	원하는 조건을 선택함 MAX:8개까지 가능              
                                    '500',                          // POP-UP뛰을때 원도우의	사용자 정의	폭                                 
                                    '500',                          // POP-UP뛰을때 우도우의	사용자 정의	높이	                           
                                    null,                           // 윈도우 위치 Y좌표	                                                   
                                    null,                           // 윈도우 위치 X좌표                                                       
                                    null,                           // 중복체크여부	("F")                                                      
                                    "T",                            // 전체검색허용여부	("F")                                                  
                                    null);							// POP-UP Window Title 검색어1,2	 ("Win타이틀,첫번검색Nm,두번?검색Nm")  			

            //cfSetReturnValue(rtnList, ed_pseq, ed_pattn, ed_pncd);

            break;
        default:
            break;
    }
}

//-------------------------------------------------------------------------
// p.o.d 출력
//-------------------------------------------------------------------------
scwin.f_Print = function () {
    var data = {
        odiName: "ar_206_01_01",
        reportName: "/il/airinb/ar_206_01_01.ozr",
        odiParam: {
            KCOMCD: scwin.hid_kcomcd,
            BLNO: ds_pod.getCellData(ds_pod.getRowPosition(),"blno")
        },
        viewerParam: {
            useprogressbar: false, // 프로그레스바 쓸지 말지
            zoom: 90, // 배율 설정
            //mode: ozMode
        },
        formParam: {

        }
    };

    scwin.openPopup(data); 
}


//-------------------------------------------------------------------------
// 오즈 리포트 팝업
//------------------------------------------------------------------------- 
scwin.openPopup = async function (data) {
    let opts = {
        id: "ozReportPopup",
        popupName: "오즈 리포트",
        modal: true,
        type: "browserPopup",
        width: 1000,
        height: 600,
        title: "오즈 리포트"
    };
    await $c.win.openPopup("/ui/cm/zz/ozreportPopup.xml", opts, data);
};

