    $c.gus.cfSetReturnValue(rtnList, cnd_ed_pncd, cnd_ed_pnnm);
}

scwin.callbackClntPicInfo = function (rtnList) {
    $c.gus.cfSetReturnValue(rtnList, ed_pseq, ed_pattn, ed_pncd);
}

